export function ResetHighlightSeries(mouse, data) {
    let manager = this,
        { chart, options, previousHighlightedItem } = manager,
        { config, highlightManager } = options,
        seriesData = chart.seriesdata;

    seriesData.forEach((d, j) => {
        highlightManager.reset(config, j, previousHighlightedItem, seriesData.length - 1 === j);
    });

    manager.previousHighlightedItem = null;
}
